def max_coins(nums):
    vals = [1] + nums + [1]
    n = len(nums)
    dp = [[0]*(n+2) for _ in range(n+2)]
    for L in range(2, n+2):
        for l in range(0, n+2-L):
            r = l + L
            best = 0
            for k in range(l+1, r):
                cand = dp[l][k] + dp[k][r] + vals[l]*vals[k]*vals[r]
                if cand > best:
                    best = cand
            dp[l][r] = best
    return dp[0][n+1]

